const { execSync } = require\(''child_process''\);
try {
  const result = execSync\(''npx next build'', { cwd: process.cwd\(\), encoding: ''utf8'', stdio: [''pipe'',''pipe'',''pipe''], timeout: 240000 }\);
  console.log\(''BUILD PASSED''\);
  // Print last 30 lines for route table
  const lines = result.split\(''\\n''\);
  console.log\(lines.slice\(-35\).join\(''\\n''\)\);
} catch\(e\) {
  const out = \(e.stdout || ''''\) + \(e.stderr || ''''\);
  // Find error lines
  const errorLines = out.split\(''\\n''\).filter\(l => l.includes\(''Error''\) || l.includes\(''error''\) || l.includes\(''Type''\)\);
  console.log\(''Error lines:'', errorLines.slice\(0, 20\).join\(''\\n''\)\);
  console.log\(''Exit:'', e.status\);
  // Full output
  console.log\(out.substring\(0, 4000\)\);
}
")
